{"path": "/tmp/sv-6074de111fa74d298ffbdf8f01a92062/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "<nav class="catalog-pagination" aria-label="Product pagination">
    <button class="page-btn"
            disabled="@(CurrentPage <= 1)"
            @onclick="@(() => GoToPage(CurrentPage - 1))">
        Previous
    </button>

    @for (int i = 1; i <= TotalPages; i++)
    {
        int pageNumber = i;
        <button class="page-btn @(pageNumber == CurrentPage ? "active" : "")"
                @onclick="@(() => GoToPage(pageNumber))">
            @pageNumber
        </button>
    }

    <button class="page-btn"
            disabled="@(CurrentPage >= TotalPages)"
            @onclick="@(() => GoToPage(CurrentPage + 1))">
        Next
    </button>
</nav>

@code {
    [Parameter]
    public int CurrentPage { get; set; } = 1;

    [Parameter]
    public int TotalPages { get; set; } = 1;

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }
}
"}

