arguments.file_text:
@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (errorMessage is not null)
{
    <div class="error-banner">
        <p>@errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (isLoading)
{
    <div class="loading-state">
        <p>Loading products…</p>
    </div>
}
else
{
    <div class="catalog-layout">
        <CatalogSidebar Categories="categories"
                        OnFilterApplied="HandleFilterApplied" />

        <main class="catalog-main">
            <CatalogToolbar SortBy="@sortBy"
                            StartItem="startItem"
                            EndItem="endItem"
                            TotalCount="totalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="products"
                         OnProductSelected="OnProductSelected"
                         OnAddToCart="HandleAddToCart" />

            @if (totalPages > 1)
            {
                <CatalogPagination CurrentPage="currentPage"
                                   TotalPages="totalPages"
                                   OnPageChanged="HandlePageChanged" />
            }
        </main>
    </div>
}

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> products = [];
    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private int pageSize = 12;
    private int totalCount;
    private int totalPages;
    private int startItem;
    private int endItem;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            categories = await categoriesTask;
            ApplyPagedResult(await productsTask);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
            ApplyPagedResult(result);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ApplyPagedResult(PagedResult<Product> result)
    {
        products = result.Items;
        totalCount = result.TotalCount;
        totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
        startItem = totalCount == 0 ? 0 : (result.Page - 1) * result.PageSize + 1;
        endItem = Math.Min(result.Page * result.PageSize, totalCount);
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 0;
    min-height: 60vh;
}

.catalog-layout > :first-child {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main {
    flex: 1;
    padding: 1rem 1.5rem;
    min-width: 0;
}

.loading-state {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 4rem 1rem;
    color: #666;
    font-size: 1.1rem;
}

.error-banner {
    background: #fee;
    border: 1px solid #fcc;
    border-radius: 8px;
    padding: 1.5rem;
    text-align: center;
    margin: 2rem auto;
    max-width: 500px;
}

.error-banner p {
    color: #c00;
    margin: 0 0 1rem;
}

.error-banner button {
    padding: 0.5rem 1.5rem;
    border: none;
    border-radius: 6px;
    background: #0078d4;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
}

