        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ApplyPagedResult(PagedResult<Product> result)
    {
        products = result.Items;
        totalCount = result.TotalCount;
        totalPages = (int)Math.Ceiling((double)result.TotalCount / result.PageSize);
        startItem = totalCount == 0 ? 0 : (result.Page - 1) * result.PageSize + 1;
        endItem = Math.Min(result.Page * result.PageSize, totalCount);
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}
